// Extract reservation link from email HTML body
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const htmlBody = item.json.html || item.json.textHtml || '';
    const textBody = item.json.text || item.json.textPlain || '';

    // Try multiple regex patterns to find reservation links
    const patterns = [
      /href=["'](https?:\/\/[^"'\s]+reservation[^"'\s]*)["']/gi,
      /href=["'](https?:\/\/[^"'\s]+\.pdf)["']/gi,
      /(https?:\/\/\S+reservation\S*)/gi,
      /(https?:\/\/\S+\.pdf)/gi
    ];

    let reservationLink = null;

    for (const pattern of patterns) {
      const matches = htmlBody.match(pattern);
      if (matches && matches.length > 0) {
        // Extract clean URL from href attribute or direct match
        if (matches[0].includes('href=')) {
          const urlMatch = matches[0].match(/href=["'](https?:\/\/[^"'\s]+)["']/);
          reservationLink = urlMatch ? urlMatch[1] : null;
        } else {
          reservationLink = matches[0];
        }
        break;
      }
    }

    // Fallback: try text body
    if (!reservationLink && textBody) {
      const textMatch = textBody.match(/(https?:\/\/\S+)/gi);
      if (textMatch && textMatch.length > 0) {
        reservationLink = textMatch[0];
      }
    }

    if (!reservationLink) {
      throw new Error('No reservation link found in email body');
    }

    results.push({
      json: {
        ...item.json,
        reservationLink: reservationLink.trim(),
        emailId: item.json.uid || item.json.messageId,
        extractedAt: new Date().toISOString()
      }
    });

  } catch (error) {
    results.push({
      json: {
        ...item.json,
        error: error.message,
        status: 'EXTRACTION_FAILED'
      }
    });
  }
}

return results;

// Check if response is HTML page containing PDF link, or direct PDF
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const contentType = item.json.headers['content-type'] || '';
    const url = item.json.reservationLink;

    let pdfUrl = url;

    // If HTML page, extract PDF link
    if (contentType.includes('text/html')) {
      const html = item.binary?.data?.toString('utf-8') || item.json.data || '';

      // Look for PDF links in HTML
      const pdfPatterns = [
        /<a[^>]+href=["'](https?:\/\/[^"']+\.pdf)["']/gi,
        /href=["'](https?:\/\/[^"']+\.pdf)["']/gi,
        /(https?:\/\/\S+\.pdf)/gi
      ];

      for (const pattern of pdfPatterns) {
        const matches = html.match(pattern);
        if (matches && matches.length > 0) {
          const urlMatch = matches[0].match(/https?:\/\/[^"'\s]+\.pdf/i);
          if (urlMatch) {
            pdfUrl = urlMatch[0];
            break;
          }
        }
      }
    }

    results.push({
      json: {
        ...item.json,
        pdfUrl: pdfUrl,
        isPdfDirect: pdfUrl === url
      }
    });

  } catch (error) {
    results.push({
      json: {
        ...item.json,
        error: error.message,
        status: 'PDF_URL_EXTRACTION_FAILED'
      }
    });
  }
}

return results;

// Parse PDF and extract reservation fields
// Requires: pdf-parse (install via npm in n8n environment)
const pdfParse = require('pdf-parse');

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Get binary PDF data
    const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');

    // Parse PDF
    const pdfData = await pdfParse(binaryData);
    const text = pdfData.text;

    // Enhanced parsing with robust field extraction
    // Handle both English and Korean labels, various spacing, and punctuation

    // Customer Name
    const namePatterns = [
      /(?:Customer|Name|고객명|예약자)[\s:：]+([^\n\r]+)/i,
      /(?:Guest)[\s:：]+([^\n\r]+)/i
    ];
    let customerName = null;
    for (const pattern of namePatterns) {
      const match = text.match(pattern);
      if (match) {
        customerName = match[1].trim();
        break;
      }
    }

    // Check-in Date (handles YY/MM/DD or YYYY/MM/DD)
    const checkinPatterns = [
      /(?:Check-?in|체크인|입실)[\s:：]+(\d{2,4}\/\d{2}\/\d{2})/i,
      /(?:Arrival)[\s:：]+(\d{2,4}\/\d{2}\/\d{2})/i
    ];
    let checkinRaw = null;
    for (const pattern of checkinPatterns) {
      const match = text.match(pattern);
      if (match) {
        checkinRaw = match[1].trim();
        break;
      }
    }

    // Rooms (integer)
    const roomsPatterns = [
      /(?:Rooms?|객실)[\s:：]+(\d+)/i,
      /(?:Room Count)[\s:：]+(\d+)/i
    ];
    let rooms = null;
    for (const pattern of roomsPatterns) {
      const match = text.match(pattern);
      if (match) {
        rooms = parseInt(match[1].trim(), 10);
        break;
      }
    }

    // Nights (integer)
    const nightsPatterns = [
      /(?:Nights?|박)[\s:：]+(\d+)/i,
      /(\d+)[\s]*(?:Nights?|박)/i
    ];
    let nights = null;
    for (const pattern of nightsPatterns) {
      const match = text.match(pattern);
      if (match) {
        nights = parseInt(match[1].trim(), 10);
        break;
      }
    }

    // Ordered At (YYYY/MM/DD HH:mm)
    const orderedAtPatterns = [
      /(?:Ordered|Reserved|예약일시|신청일)[\s:：]+(\d{4}\/\d{2}\/\d{2}[\s]+\d{2}:\d{2})/i,
      /(?:Request Date)[\s:：]+(\d{4}\/\d{2}\/\d{2}[\s]+\d{2}:\d{2})/i
    ];
    let orderedAtRaw = null;
    for (const pattern of orderedAtPatterns) {
      const match = text.match(pattern);
      if (match) {
        orderedAtRaw = match[1].trim();
        break;
      }
    }

    // Hotel Name (optional, for fuzzy matching)
    const hotelPatterns = [
      /(?:Hotel|호텔명)[\s:：]+([^\n\r]+)/i,
      /(?:Property)[\s:：]+([^\n\r]+)/i
    ];
    let hotelNameRaw = null;
    for (const pattern of hotelPatterns) {
      const match = text.match(pattern);
      if (match) {
        hotelNameRaw = match[1].trim();
        break;
      }
    }

    // Validation
    const missingFields = [];
    if (!customerName) missingFields.push('customer_name');
    if (!checkinRaw) missingFields.push('checkin');
    if (!rooms) missingFields.push('rooms');
    if (!nights) missingFields.push('nights');
    if (!orderedAtRaw) missingFields.push('ordered_at');

    if (missingFields.length > 0) {
      throw new Error(`Missing required fields: ${missingFields.join(', ')}`);
    }

    results.push({
      json: {
        ...item.json,
        parsedData: {
          customer_name: customerName,
          checkin_raw: checkinRaw,
          rooms: rooms,
          nights: nights,
          ordered_at_raw: orderedAtRaw,
          hotel_name_en_raw: hotelNameRaw
        },
        pdfText: text,
        parseStatus: 'SUCCESS'
      }
    });

  } catch (error) {
    results.push({
      json: {
        ...item.json,
        error: error.message,
        status: 'PDF_PARSE_FAILED',
        parseStatus: 'FAILED'
      }
    });
  }
}

return results;

// Normalize date formats to ISO standards
const items = $input.all();
const results = [];

function normalizeCheckin(rawDate) {
  // Pattern: YY/MM/DD (e.g., 25/07/12)
  const yyPattern = /^(\d{2})\/(\d{2})\/(\d{2})$/;
  // Pattern: YYYY/MM/DD (e.g., 2025/07/12)
  const yyyyPattern = /^(\d{4})\/(\d{2})\/(\d{2})$/;

  if (yyPattern.test(rawDate)) {
    const [, yy, mm, dd] = rawDate.match(yyPattern);
    // Assume 20XX for years < 70, 19XX for years >= 70
    const yyyy = parseInt(yy, 10) < 70 ? `20${yy}` : `19${yy}`;
    return `${yyyy}-${mm}-${dd}`;
  }

  if (yyyyPattern.test(rawDate)) {
    const [, yyyy, mm, dd] = rawDate.match(yyyyPattern);
    return `${yyyy}-${mm}-${dd}`;
  }

  throw new Error(`Unsupported check-in date format: ${rawDate}`);
}

function normalizeOrderedAt(rawDateTime) {
  // Pattern: YYYY/MM/DD HH:mm (e.g., 2025/09/19 14:12)
  // Simply replace / with -
  const pattern = /^(\d{4})\/(\d{2})\/(\d{2})([\s]+\d{2}:\d{2})$/;

  if (pattern.test(rawDateTime)) {
    return rawDateTime.replace(/\//g, '-');
  }

  throw new Error(`Unsupported ordered_at format: ${rawDateTime}`);
}

for (const item of items) {
  try {
    const parsed = item.json.parsedData;

    const checkin = normalizeCheckin(parsed.checkin_raw);
    const orderedAt = normalizeOrderedAt(parsed.ordered_at_raw);

    results.push({
      json: {
        ...item.json,
        normalizedData: {
          customer_name: parsed.customer_name,
          checkin: checkin,
          rooms: parsed.rooms,
          nights: parsed.nights,
          ordered_at: orderedAt,
          hotel_name_en_raw: parsed.hotel_name_en_raw
        },
        normalizationStatus: 'SUCCESS'
      }
    });

  } catch (error) {
    results.push({
      json: {
        ...item.json,
        error: error.message,
        status: 'DATE_NORMALIZATION_FAILED'
      }
    });
  }
}

return results;

// Fuzzy match hotel name using Levenshtein distance
// Returns best match or flags for manual review

const items = $input.all();
const results = [];

// Levenshtein distance implementation
function levenshteinDistance(str1, str2) {
  const matrix = [];

  for (let i = 0; i <= str2.length; i++) {
    matrix[i] = [i];
  }

  for (let j = 0; j <= str1.length; j++) {
    matrix[0][j] = j;
  }

  for (let i = 1; i <= str2.length; i++) {
    for (let j = 1; j <= str1.length; j++) {
      if (str2.charAt(i - 1) === str1.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1,
          matrix[i][j - 1] + 1,
          matrix[i - 1][j] + 1
        );
      }
    }
  }

  return matrix[str2.length][str1.length];
}

function similarity(str1, str2) {
  const longer = str1.length > str2.length ? str1 : str2;
  const shorter = str1.length > str2.length ? str2 : str1;

  if (longer.length === 0) {
    return 1.0;
  }

  return (longer.length - levenshteinDistance(longer, shorter)) / longer.length;
}

// Get hotel master data (assumes last item contains all hotel records)
const hotelMasterItems = items.filter(item => item.json.hotel_name_en);

for (const item of items) {
  try {
    // Skip hotel master records themselves
    if (item.json.hotel_name_en && !item.json.normalizedData) {
      continue;
    }

    const normalized = item.json.normalizedData;
    const searchName = normalized.hotel_name_en_raw;

    if (!searchName) {
      throw new Error('No hotel name found in PDF for matching');
    }

    // Perform fuzzy matching
    let bestMatch = null;
    let bestScore = 0;
    const threshold = parseFloat(process.env.HOTEL_MATCH_THRESHOLD || '0.85');

    for (const hotelRecord of hotelMasterItems) {
      const masterName = hotelRecord.json.hotel_name_en;
      const score = similarity(
        searchName.toLowerCase().trim(),
        masterName.toLowerCase().trim()
      );

      if (score > bestScore) {
        bestScore = score;
        bestMatch = hotelRecord.json;
      }
    }

    // Check if match meets threshold
    if (bestScore >= threshold && bestMatch) {
      results.push({
        json: {
          ...item.json,
          hotelMapping: {
            hotel_name_en: bestMatch.hotel_name_en,
            hotel_code: bestMatch.hotel_code,
            product_code: bestMatch.product_code,
            match_score: bestScore,
            search_name: searchName
          },
          mappingStatus: 'MATCHED'
        }
      });
    } else {
      // Needs manual review
      results.push({
        json: {
          ...item.json,
          hotelMapping: {
            hotel_name_en: bestMatch ? bestMatch.hotel_name_en : 'NO_MATCH',
            hotel_code: null,
            product_code: null,
            match_score: bestScore,
            search_name: searchName
          },
          mappingStatus: 'NEEDS_REVIEW',
          error: `Hotel match score ${bestScore.toFixed(2)} below threshold ${threshold}`
        }
      });
    }

  } catch (error) {
    results.push({
      json: {
        ...item.json,
        error: error.message,
        status: 'HOTEL_MATCHING_FAILED',
        mappingStatus: 'FAILED'
      }
    });
  }
}

return results.filter(r => r.json.normalizedData); // Filter out hotel master records

// Prepare Excel data for successful matches
const items = $input.all();
const results = [];

for (const item of items) {
  const normalized = item.json.normalizedData;
  const mapping = item.json.hotelMapping;

  // Generate output filename with timestamp
  const now = new Date();
  const timestamp = now.toISOString().replace(/[-:]/g, '').replace('T', '_').split('.')[0];
  const outputDir = process.env.OUTPUT_DIR || '/tmp';
  const outputPath = `${outputDir}/reservation_upload_${timestamp}.xlsx`;

  results.push({
    json: {
      ...item.json,
      excelData: {
        customer_name: normalized.customer_name,
        checkin: normalized.checkin,
        rooms: normalized.rooms,
        nights: normalized.nights,
        ordered_at: normalized.ordered_at,
        hotel_name_en: mapping.hotel_name_en,
        hotel_code: mapping.hotel_code,
        product_code: mapping.product_code
      },
      outputPath: outputPath,
      timestamp: timestamp
    }
  });
}

return results;

// Playwright automation for admin portal upload
// This script handles the full browser automation flow

const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const items = $input.all();
const results = [];

for (const item of items) {
  const filePath = item.json.outputPath;
  const adminUser = process.env.ADMIN_USER;
  const adminPass = process.env.ADMIN_PASS;
  const outputDir = process.env.OUTPUT_DIR || '/tmp';

  let browser = null;
  let uploadSuccess = false;

  try {
    // Validate file exists
    if (!fs.existsSync(filePath)) {
      throw new Error(`Excel file not found: ${filePath}`);
    }

    // Launch browser
    browser = await chromium.launch({
      headless: process.env.PLAYWRIGHT_HEADLESS !== 'false',
      args: ['--no-sandbox', '--disable-setuid-sandbox']
    });

    const context = await browser.newContext({
      viewport: { width: 1280, height: 900 },
      userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
    });

    const page = await context.newPage();

    // Enable console logging for debugging
    page.on('console', msg => console.log('Browser console:', msg.text()));

    // Step 1: Navigate to admin portal
    console.log('Navigating to admin portal...');
    await page.goto('https://adm.allmytour.com', {
      waitUntil: 'domcontentloaded',
      timeout: 30000
    });

    // Take screenshot for debugging
    await page.screenshot({ path: `${outputDir}/01_login_page.png` });

    // Step 2: Login
    console.log('Logging in...');
    await page.waitForSelector('input[name="username"], input[type="text"]', { timeout: 10000 });
    await page.fill('input[name="username"], input[type="text"]', adminUser);
    await page.fill('input[name="password"], input[type="password"]', adminPass);

    // Click login button (try multiple selectors)
    const loginSelectors = [
      'button:has-text("로그인")',
      'button[type="submit"]',
      'input[type="submit"]',
      'button.login-btn'
    ];

    let loginClicked = false;
    for (const selector of loginSelectors) {
      try {
        await page.click(selector, { timeout: 2000 });
        loginClicked = true;
        break;
      } catch (e) {
        continue;
      }
    }

    if (!loginClicked) {
      throw new Error('Could not find login button');
    }

    // Wait for navigation after login
    await page.waitForLoadState('networkidle', { timeout: 15000 });
    await page.screenshot({ path: `${outputDir}/02_after_login.png` });

    // Step 3: Navigate to 판매관리 (Sales Management)
    console.log('Navigating to Sales Management...');
    await page.waitForSelector('text=판매관리', { timeout: 10000 });
    await page.click('text=판매관리');
    await page.waitForTimeout(1000);
    await page.screenshot({ path: `${outputDir}/03_sales_menu.png` });

    // Step 4: Navigate to 예약목록 (Reservation List)
    console.log('Navigating to Reservation List...');
    await page.waitForSelector('text=예약목록', { timeout: 10000 });
    await page.click('text=예약목록');
    await page.waitForLoadState('networkidle', { timeout: 15000 });
    await page.screenshot({ path: `${outputDir}/04_reservation_list.png` });

    // Step 5: Scroll to bottom to find upload section
    console.log('Scrolling to upload section...');
    await page.evaluate(() => {
      window.scrollTo(0, document.body.scrollHeight);
    });
    await page.waitForTimeout(1000);
    await page.screenshot({ path: `${outputDir}/05_scroll_bottom.png` });

    // Step 6: Find and populate file input
    console.log('Uploading file...');
    await page.waitForSelector('input[type="file"]', { timeout: 10000 });
    const fileInput = await page.$('input[type="file"]');

    if (!fileInput) {
      throw new Error('File input not found');
    }

    await fileInput.setInputFiles(filePath);
    await page.waitForTimeout(2000);
    await page.screenshot({ path: `${outputDir}/06_file_selected.png` });

    // Step 7: Click 예약등록 (Register Reservation) button
    console.log('Clicking Register button...');
    const registerSelectors = [
      'button:has-text("예약등록")',
      'input:has-text("예약등록")',
      'button.register-btn',
      'button[type="submit"]:has-text("등록")'
    ];

    let registerClicked = false;
    for (const selector of registerSelectors) {
      try {
        await page.click(selector, { timeout: 2000 });
        registerClicked = true;
        break;
      } catch (e) {
        continue;
      }
    }

    if (!registerClicked) {
      throw new Error('Could not find register button');
    }

    await page.waitForTimeout(2000);

    // Step 8: Handle popup modal - click 취소 (Cancel)
    console.log('Handling confirmation modal...');
    try {
      await page.waitForSelector('.modal-dialog, [role="dialog"], .modal', { timeout: 10000 });
      await page.screenshot({ path: `${outputDir}/07_modal_appeared.png` });

      const cancelSelectors = [
        'button:has-text("취소")',
        '.modal button:has-text("취소")',
        '[role="dialog"] button:has-text("취소")',
        'button.cancel-btn'
      ];

      let cancelClicked = false;
      for (const selector of cancelSelectors) {
        try {
          await page.click(selector, { timeout: 2000 });
          cancelClicked = true;
          break;
        } catch (e) {
          continue;
        }
      }

      if (!cancelClicked) {
        console.warn('Could not find cancel button, modal might have auto-closed');
      }

      await page.waitForTimeout(1000);
      await page.screenshot({ path: `${outputDir}/08_final_state.png` });

    } catch (modalError) {
      console.warn('Modal handling error (may be expected):', modalError.message);
      await page.screenshot({ path: `${outputDir}/08_no_modal.png` });
    }

    uploadSuccess = true;
    console.log('Upload automation completed successfully');

    results.push({
      json: {
        ...item.json,
        uploadStatus: 'SUCCESS',
        uploadTimestamp: new Date().toISOString()
      }
    });

  } catch (error) {
    console.error('Upload automation error:', error);

    // Capture error screenshot
    if (browser) {
      try {
        const pages = await browser.contexts()[0].pages();
        if (pages.length > 0) {
          await pages[0].screenshot({ path: `${outputDir}/error_screenshot.png` });
        }
      } catch (screenshotError) {
        console.error('Could not capture error screenshot:', screenshotError);
      }
    }

    results.push({
      json: {
        ...item.json,
        uploadStatus: 'FAILED',
        uploadError: error.message,
        uploadTimestamp: new Date().toISOString()
      }
    });

  } finally {
    if (browser) {
      await browser.close();
    }
  }
}

return results;
